# main.py
"""
Google Cloud Function that processes files from Cloud Storage,
writes to Firestore, and publishes to Pub/Sub.

Security: Uses least-privilege permissions instead of broad admin roles.
- Storage Object Viewer (not Storage Admin) - only needs to read files
- Cloud Datastore User (scoped to specific collection) - only needs to write documents
- Pub/Sub Publisher (scoped to specific topic) - only needs to publish messages
"""

import json
import os
import logging
from datetime import datetime, timezone
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
from google.api_core import exceptions as gcp_exceptions
from google.api_core import retry

# Configure structured logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Configuration via environment variables (not hardcoded)
PROJECT_ID = os.environ.get("GCP_PROJECT_ID")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC_ID", "file-processing-results")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")
ALLOWED_BUCKET = os.environ.get("ALLOWED_BUCKET", "")
ALLOWED_FILE_EXTENSIONS = os.environ.get(
    "ALLOWED_FILE_EXTENSIONS", ".json,.csv,.txt"
).split(",")
MAX_FILE_SIZE_BYTES = int(os.environ.get("MAX_FILE_SIZE_BYTES", str(50 * 1024 * 1024)))  # 50MB default


def _validate_event_data(event: dict) -> tuple[str, str]:
    """Validate and extract bucket/file info from the Cloud Storage event."""
    bucket_name = event.get("bucket")
    file_name = event.get("name")
    file_size = int(event.get("size", 0))

    if not bucket_name or not file_name:
        raise ValueError("Event missing required 'bucket' or 'name' fields")

    # Prevent path traversal attacks
    if ".." in file_name or file_name.startswith("/"):
        raise ValueError(f"Invalid file path detected: {file_name}")

    # Validate bucket is the expected one (defense in depth)
    if ALLOWED_BUCKET and bucket_name != ALLOWED_BUCKET:
        raise ValueError(
            f"Unexpected bucket '{bucket_name}'. Expected '{ALLOWED_BUCKET}'"
        )

    # Validate file extension
    if not any(file_name.lower().endswith(ext) for ext in ALLOWED_FILE_EXTENSIONS):
        raise ValueError(
            f"File extension not allowed for '{file_name}'. "
            f"Allowed: {ALLOWED_FILE_EXTENSIONS}"
        )

    # Validate file size
    if file_size > MAX_FILE_SIZE_BYTES:
        raise ValueError(
            f"File size {file_size} exceeds maximum {MAX_FILE_SIZE_BYTES} bytes"
        )

    return bucket_name, file_name


def _read_file_from_storage(bucket_name: str, file_name: str) -> bytes:
    """Read file content from Cloud Storage with minimal permissions."""
    # Client uses the function's service account credentials automatically
    storage_client = storage.Client(project=PROJECT_ID)
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    if not blob.exists():
        raise FileNotFoundError(f"File {file_name} not found in bucket {bucket_name}")

    # Re-check size server-side (defense in depth against spoofed events)
    blob.reload()
    if blob.size and blob.size > MAX_FILE_SIZE_BYTES:
        raise ValueError(f"File size {blob.size} exceeds limit on server-side check")

    content = blob.download_as_bytes(timeout=60)
    return content


def _process_file_content(file_name: str, content: bytes) -> dict:
    """Process the file content and return structured results."""
    result = {
        "file_name": file_name,
        "file_size_bytes": len(content),
        "processed_at": datetime.now(timezone.utc).isoformat(),
        "status": "processed",
    }

    if file_name.lower().endswith(".json"):
        try:
            parsed = json.loads(content.decode("utf-8"))
            result["record_count"] = (
                len(parsed) if isinstance(parsed, list) else 1
            )
            result["content_type"] = "json"
            result["data_summary"] = _summarize_json(parsed)
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            result["status"] = "parse_error"
            result["error"] = f"JSON parse error: {str(e)}"

    elif file_name.lower().endswith(".csv"):
        try:
            text = content.decode("utf-8")
            lines = text.strip().split("\n")
            result["record_count"] = max(0, len(lines) - 1)  # Exclude header
            result["content_type"] = "csv"
            if lines:
                result["columns"] = lines[0].split(",")
        except UnicodeDecodeError as e:
            result["status"] = "parse_error"
            result["error"] = f"CSV decode error: {str(e)}"

    elif file_name.lower().endswith(".txt"):
        try:
            text = content.decode("utf-8")
            result["line_count"] = len(text.strip().split("\n"))
            result["content_type"] = "text"
            result["char_count"] = len(text)
        except UnicodeDecodeError as e:
            result["status"] = "parse_error"
            result["error"] = f"Text decode error: {str(e)}"

    return result


def _summarize_json(data) -> dict:
    """Create a safe summary of JSON data without exposing sensitive content."""
    summary = {"type": type(data).__name__}
    if isinstance(data, list):
        summary["length"] = len(data)
        if data and isinstance(data[0], dict):
            summary["sample_keys"] = list(data[0].keys())[:10]
    elif isinstance(data, dict):
        summary["keys"] = list(data.keys())[:10]
    return summary


@retry.Retry(predicate=retry.if_exception_type(gcp_exceptions.ServiceUnavailable))
def _write_to_firestore(doc_id: str, data: dict) -> None:
    """Write processing results to Firestore."""
    db = firestore.Client(project=PROJECT_ID)

    # Sanitize document ID - use only safe characters
    safe_doc_id = doc_id.replace("/", "_").replace("..", "")[:1500]

    # Write to a specific collection only (least privilege at application level)
    doc_ref = db.collection(FIRESTORE_COLLECTION).document(safe_doc_id)

    # Add metadata
    data["_created_at"] = firestore.SERVER_TIMESTAMP
    data["_source"] = "file-processor-function"

    doc_ref.set(data)
    logger.info(f"Written document '{safe_doc_id}' to Firestore collection '{FIRESTORE_COLLECTION}'")


@retry.Retry(predicate=retry.if_exception_type(gcp_exceptions.ServiceUnavailable))
def _publish_to_pubsub(data: dict) -> str:
    """Publish processing results to Pub/Sub topic."""
    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)

    # Serialize and publish
    message_data = json.dumps(data, default=str).encode("utf-8")

    # Add attributes for filtering/routing
    attributes = {
        "source": "file-processor-function",
        "status": data.get("status", "unknown"),
        "content_type": data.get("content_type", "unknown"),
    }

    future = publisher.publish(
        topic_path,
        data=message_data,
        **attributes,
    )
    message_id = future.result(timeout=30)
    logger.info(f"Published message {message_id} to topic '{PUBSUB_TOPIC}'")
    return message_id


def process_file(event: dict, context) -> dict:
    """
    Cloud Function entry point triggered by Cloud Storage events.

    Args:
        event: Cloud Storage event payload
        context: Event metadata (event ID, timestamp, etc.)
    """
    logger.info(
        f"Processing event {context.event_id} for resource {context.resource}"
    )

    try:
        # 1. Validate input
        bucket_name, file_name = _validate_event_data(event)
        logger.info(f"Processing file: gs://{bucket_name}/{file_name}")

        # 2. Read file from Cloud Storage (requires: storage.objects.get)
        content = _read_file_from_storage(bucket_name, file_name)

        # 3. Process file content
        result = _process_file_content(file_name, content)
        result["bucket"] = bucket_name
        result["event_id"] = context.event_id

        # 4. Write results to Firestore (requires: datastore.entities.create/update)
        doc_id = f"{bucket_name}_{file_name}_{context.event_id}"
        _write_to_firestore(doc_id, result.copy())

        # 5. Publish notification to Pub/Sub (requires: pubsub.topics.publish)
        message_id = _publish_to_pubsub(result)
        result["pubsub_message_id"] = message_id

        logger.info(f"Successfully processed {file_name}: {result['status']}")
        return result

    except ValueError as e:
        logger.warning(f"Validation error: {e}")
        _publish_error_to_pubsub(event, context, str(e))
        return {"status": "validation_error", "error": str(e)}

    except FileNotFoundError as e:
        logger.warning(f"File not found: {e}")
        return {"status": "not_found", "error": str(e)}

    except gcp_exceptions.PermissionDenied as e:
        # Log but don't expose internal permission details
        logger.error(f"Permission denied during processing: {e}")
        return {"status": "error", "error": "Insufficient permissions"}

    except Exception as e:
        logger.error(f"Unexpected error processing {event.get('name', 'unknown')}: {e}")
        return {"status": "error", "error": "Internal processing error"}


def _publish_error_to_pubsub(event: dict, context, error_msg: str) -> None:
    """Publish error notifications for monitoring/alerting."""
    try:
        error_data = {
            "status": "error",
            "file_name": event.get("name", "unknown"),
            "bucket": event.get("bucket", "unknown"),
            "error": error_msg,
            "event_id": context.event_id if context else "unknown",
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }
        _publish_to_pubsub(error_data)
    except Exception as e:
        logger.error(f"Failed to publish error notification: {e}")